	public void addResolution() throws Exception {
		try {
			if(actions.isElementPresent(RequestLocators.Admin.Notification.SMILEY_DROPDOWN)) {
				actions.click(RequestLocators.Admin.Notification.SMILEY_DROPDOWN);
				actions.waitForAnElementToAppear(RequestLocators.Admin.Notification.SMILEY, 10);
				
				actions.click(RequestLocators.Admin.Notification.SMILEY);
				actions.waitForAnElementToAppear(RequestLocators.Admin.Notification.SMILE, 10);
				actions.click(RequestLocators.Admin.Notification.SMILE);
			}else {
				actions.click(RequestLocators.Admin.Notification.SMILEY);
				actions.click(RequestLocators.Admin.Notification.SMILE);
			}
		}catch(Exception e) {
			addFailureReport("Failed in addResolution()", e.getMessage());
		}
	}
	
