	@AutomaterScenario(
		group = "RequestFAFR",
		priority = Priority.MEDIUM,
		dataIds = {},
		tags = {},
		description = "Test Set Value to Field Action execute on field Change",
		id = "SDPOD-FL-S-FAFR-0920"
	)
	public void checkSetValueToItemFieldActionExecuteOnFieldChange() {
		try {
			String templateName = random.generateRandomString(4);
			addTemplate(templateName);
			LocalStorage.store("moduleName", getFafrModuleName());
			
			// Resolve entity IDs for hierarchical fields
			String categoryId = TriggerAPIUtil.getEntityIdforCriteriaValue("requests/category", "Software");
			String subCategoryId = TriggerAPIUtil.getEntityIdforCriteriaValue("categories/" + categoryId + "/subcategories", "MS Office");
			String itemId = TriggerAPIUtil.getEntityIdforCriteriaValue("categories/" + categoryId + "/subcategories/" + subCategoryId + "/items", "Install");
			
			// Rule 1 (On Form Load): set_value category = Software
			JSONObject oflData1 = DataUtil.getTestCaseDataUsingFilePath(path, "fafr_action_ofl");
			JSONArray actionsArray1 = oflData1.getJSONObject("request_fafr").getJSONArray("actions");
			actionsArray1.put(FAFRAPIUtil.buildOptionAction("set_value", "category", categoryId, "Software"));
			FAFRAPIUtil.createRequestFAFR2(oflData1);
			LocalStorage.store("fafrId1", LocalStorage.getAsString("fafrId"));
			
			// Rule 2 (On Form Load): set_value subcategory = MS Office « Software
			JSONObject oflData2 = DataUtil.getTestCaseDataUsingFilePath(path, "fafr_action_ofl");
			JSONArray actionsArray2 = oflData2.getJSONObject("request_fafr").getJSONArray("actions");
			actionsArray2.put(FAFRAPIUtil.buildOptionAction("set_value", "subcategory", subCategoryId, "MS Office « Software"));
			FAFRAPIUtil.createRequestFAFR2(oflData2);
			LocalStorage.store("fafrId2", LocalStorage.getAsString("fafrId"));
			
			// Rule 3 (On Field Change - group): set_value item = Install « MS Office « Software
			LocalStorage.store("onFieldChangeOf", "group");
			JSONObject ofcData = DataUtil.getTestCaseDataUsingFilePath(path, "fafr_action_ofc");
			JSONArray actionsArray3 = ofcData.getJSONObject("request_fafr").getJSONArray("actions");
			actionsArray3.put(FAFRAPIUtil.buildOptionAction("set_value", "item", itemId, "Install « MS Office « Software"));
			FAFRAPIUtil.createRequestFAFR2(ofcData);
			
			openRequestAddFormFromLocalStorage();
			actions.formBuilder.fillSelectField(RequestFields.GROUP.getName(), RequestConstants.FieldValues.GROUP_HARDWAREPROBLEMS);
			String actualItemText = actions.getText(ClientFrameworkLocators.FormBuilderLocators.SELECT_ELEMENT.apply(RequestFields.ITEM.getName()));
			if(actualItemText.equals(RequestConstants.FieldValues.ITEM_INSTALL)) {
				addSuccessReport("Rule was executed successfully");
			}else {
				addFailureReport("Unable to execute the Rule", "Expected: '" + RequestConstants.FieldValues.ITEM_INSTALL + "' but got: '" + actualItemText + "'");
			}
		}catch(Exception exception) {
			addFailureReport("Exception occured while running the case", exception.getMessage());
		}
	}
	
