			String id = addFafrRuleHideUdf(udfkey);
			goToFormRulesInAdminTab();
			chooseFormRule();
			actions.click(AdminLocators.RequestFAFR.GEAR_ICON.apply(id));
			actions.click(AdminLocators.RequestFAFR.EDIT_RULE_UNDER_GEAR_ICON.apply(id));
