	/** Finds the request by subject via REST API and stores its internal ID as request_id in LocalStorage for postProcess cleanup */
	public void storeRequestIdBySubject(String subject) throws Exception {
		String internalId = restAPI.getEntityIDUsingFieldValue("requests", "subject", subject);
		LocalStorage.store("request_id", internalId);
	}
	
	public JSONObject createRequest(JSONObject template) throws Exception {
		LocalStorage.store("template_id", template.getString(RequestFields.ID.getDataPath()));
		JSONObject json = restAPI.createAndGetResponse(RequestsEntities.REQUEST, RequestAPIPaths.REQUESTS, getTestCaseData(RequestDataConstants.FafrData.ADD_REQUEST));
		String reqid = json.getString("id");
		LocalStorage.store("request_id", reqid);
		return json;
	}
	
	/** Creates a request using template_id already stored in LocalStorage (stored by addTemplate/preProcess) */
	public JSONObject createRequestFromLocalStorage() throws Exception {
		JSONObject json = restAPI.createAndGetResponse(RequestsEntities.REQUEST, RequestAPIPaths.REQUESTS, getTestCaseData(RequestDataConstants.FafrData.ADD_REQUEST));
		String reqid = json.getString("id");
		LocalStorage.store("request_id", reqid);
		if(json.has("display_id")) {
			LocalStorage.store("request_display_id", json.getString("display_id"));
		}
		return json;
	}
	
