		JSONObject response = restAPI.createAndGetResponse(RequestsEntities.REQUEST_TEMPLATE, RequestAPIPaths.REQUEST_TEMPLATES, getTestCaseData(RequestDataConstants.FafrData.SIMPLE_SERVICE_TEMPLATE));
