	public void rejectTheRequest(String requestId) throws Exception {
		openRequestUsingShortCut(requestId);
		actions.waitForAjaxComplete();
		requestDetailActions.toApprovalTab();
		actions.click(RequestLocators.RequestFAFR.MANAGE_APPROVALS_ICON);
		actions.type(RequestLocators.RequestFAFR.SELECT_STAGE1_APPROVARS, actions.getLoggedInUser());
		actions.waitForAjaxComplete();
		actions.click(ClientFrameworkLocators.FormBuilderLocators.OPTION_ELEMENT.apply(actions.getLoggedInUser() + " [ " + actions.getLoggedInUserMailId() + " ]"));
		actions.click(RequestLocators.RequestFAFR.SAVE_AND_SEND_BUTTON);
		actions.click(RequestLocators.RequestFAFR.STAGE1_LABEL);
		actions.click(RequestLocators.DetailView.CLICK_TAKE_ACTION_IN_APPROVALS_STAGE);
		actions.click(RequestApprovalsLocators.Popup.APPROVAL_ACTION_REJECT);
		actions.admin.popupFormBuilder.fillTextAreaField("approval_action_comment", "Reject");
		actions.click(WorkflowsLocators.Listview.APPROVAL_COMMENT_SUBMIT);
		WaitUtil.sleep(2l);
		// actions.click(RequestLocators.Listview.CLICK_REJECT_BTN_IN_APPPROVALS_ICON);
		// actions.click(RequestLocators.RequestFAFR.REJECT_REQUEST);
		// actions.click(RequestLocators.Global.SAVE_BUTTON);
	}
	
	public void assignDepartmentForRequester(String requesterMailId, String department) {
		try {
			// actions.navigate.toAdmin();
			// actions.refreshPage();
			AdminActionsUtil.gotoentity(AdminConstants.SubModule.USERS);
			// actions.click(RequestLocators.DetailView.CLICK_ADMIN_TAB.apply(RequestConstants.PORTALSETTINGS.USER));
			actions.click(RequestLocators.DetailView.USER_DROPDOWN);
			actions.click(RequestLocators.DetailView.CLICK_USER.apply("requester"));
			actions.waitForAjaxComplete();
			actions.click(RequestLocators.Listview.ICON_SEARCH);
			WebElement emailSearch = actions.getElement(AdminLocators.SEARCH_REQUESTER_WITH_EMAIL);
			emailSearch.sendKeys(requesterMailId);
			emailSearch.sendKeys(Keys.ENTER);
			actions.click(AdminLocators.SELECT_FIRST_REQUESTER);
			actions.click(RequestLocators.Admin.Technician.TECHNICIAN_DEPARTMENT);
			actions.formBuilder.typeAndSelectOption(department);
			actions.click(AdminLocators.FORM_SAVE_BUTTON);
		}catch(Exception exception) {
			addFailureReport("Exception occured while running the case", exception.getMessage());
		}
	}
	
