	public String getFAFRId(String fafr) throws BadResponseException, JSONException, SeleniumException, FileNotFoundException, DataNotFoundException {
		JSONObject fafrs = getTestCaseData(RequestDataConstants.Filter.GET_ID);
		JSONObject template1 = restAPI.get("request_fafr" + "/", fafrs);
		JSONArray ddStr = template1.getJSONArray("request_fafr");
		String idString = null;
		for(int i = 0; i < ddStr.length(); i++) {
			JSONObject objectInArray = ddStr.getJSONObject(i);
			String name1 = objectInArray.getString("name");
			if(name1.equals(fafr)) {
				idString = objectInArray.getString("id");
				break;
			}
		}
		return idString;
	}
	
	public void addResolutionCheckFafr() {
		report.startMethodFlowInStepsToReproduce(AutomaterVariables.SCENARIO_START.apply(getMethodName()));
		
		try {
			// RequestActionsUtils.navigateTo(null, null);
			// RequestActionsUtils.navigateTo(getEntityId(), RequestConstants.DetailsPageTabs.RESOLUTION);
			requestDetailActions.toResolutionTab();
			JSONObject inputData = getTestCaseData(RequestDataConstants.RequestData.RESOLTUION_TEXT);
			String resolution = AutomaterUtil.getValueAsStringFromInputUsingAPIPath(inputData, RequestFields.RESOLUTION.getDataPath());
			RequestActionsUtils.addNotesContent(resolution);
			actions.clickByName(GlobalConstants.Actions.SAVE);
			Boolean isEquals = actions.isElementPresent(RequestLocators.DetailView.RESOLUTION_TEXT.apply(resolution));
			
			if(isEquals) {
				addSuccessReport("Resolution Added Successfully");
			}else {
				addFailureReport("Adding resolution Failed", "Resolution not added");
			}
		}catch(Exception exception) {
			addFailureReport(RequestConstants.Messages.INTERNAL_ERROR + getMethodName(), exception.getMessage());
		}finally {
			report.endMethodFlowInStepsToReproduce();
		}
	}
	
	public String getReqId(String fafr) throws BadResponseException, JSONException, SeleniumException, FileNotFoundException, DataNotFoundException {
		JSONObject req = getTestCaseData(RequestDataConstants.RequestDetailsPage.GET_ID);
		JSONObject template1 = restAPI.get("requests" + "/", req);
		JSONArray ddStr = template1.getJSONArray("requests");
		String idString = null;
		for(int i = 0; i < ddStr.length(); i++) {
			JSONObject objectInArray = ddStr.getJSONObject(i);
			String name1 = objectInArray.getJSONObject("template").getString("name");
			if(name1.equals(fafr)) {
				idString = objectInArray.getString("id");
				break;
			}
		}
		return idString;
	}
	
