	@AutomaterScenario(
		group = "",
		priority = Priority.MEDIUM,
		dataIds = {},
		tags = {},
		description = "Test Gear Icon in Specify Rule",
		runType = ScenarioRunType.USER_BASED,// check
		id = "SDPOD-FL-S-FAFR-0007"
	)
	public void checkDisableRulePresentUnderGearIcon() {
		try {
			actions.navigate.toAdmin();
			String ruleId = addEnableRuleWithTemplates(random.generateRandomString(4), addTemplate(random.generateRandomString(4)), random.generateRandomString(4));
			goToFormRulesInAdminTab();
			chooseFormRule();
			recordPerPageFromTable();
			boolean success = actions.isElementPresent(AdminLocators.RequestFAFR.GEAR_ICON.apply(ruleId));
			if(!success) {
				actions.click(AdminLocators.RequestFAFR.NEXT_PAGE);
			}
			actions.click(AdminLocators.RequestFAFR.GEAR_ICON.apply(ruleId));
			if(actions.isElementPresent(AdminLocators.RequestFAFR.DISABLE_RULE_UNDER_GEAR_ICON.apply(ruleId)) && !actions.isElementPresent(AdminLocators.RequestFAFR.ENABLE_RULE_UNDER_GEAR_ICON.apply(ruleId))) {
				addSuccessReport("Disable Rule function is present");
			}else {
				addFailureReport("Failed to check disable rule function", "Disable Rule function is not present");
			}
		}catch(Exception exception) {
			addFailureReport("Exception occured while running the case", exception.getMessage());
		}
	}
	
